import React, { useEffect, useState } from 'react';
import { getTasks, getResponsesForTask, getRatingsForResponse, createRating } from '../services/api';

interface Task {
  id: number;
  prompt: string;
  status: string;
}

interface Response {
  id: number;
  task_id: number;
  ai_model: string;
  response_text: string;
  response_time: number;
}

interface Rating {
  id: number;
  response_id: number;
  annotator_id: number;
  score: number;
  feedback: string;
}

const RatingsPage: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [selectedTask, setSelectedTask] = useState<number | null>(null);
  const [responses, setResponses] = useState<Response[]>([]);
  const [ratings, setRatings] = useState<{ [key: number]: Rating[] }>({});
  const [scores, setScores] = useState<{ [key: number]: number }>({});
  const [feedbacks, setFeedbacks] = useState<{ [key: number]: string }>({});
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => { fetchTasks(); }, []);

  const fetchTasks = async () => {
    try {
      const data = await getTasks();
      setTasks(data);
    } catch (err) {
      setError('Failed to load tasks');
    }
  };

  const handleSelectTask = async (taskId: number) => {
    setSelectedTask(taskId);
    setError('');
    setSuccess('');
    setResponses([]);
    setRatings({});
    try {
      const data = await getResponsesForTask(taskId);
      setResponses(data);
      for (const response of data) {
        const ratingData = await getRatingsForResponse(response.id);
        setRatings(prev => ({ ...prev, [response.id]: ratingData }));
      }
    } catch (err) {
      setError('Failed to load responses');
    }
  };

  const handleSubmitRating = async (responseId: number) => {
    const score = scores[responseId];
    const feedback = feedbacks[responseId] || '';
    if (!score) { setError('Please select a score'); return; }
    try {
      await createRating({ response_id: responseId, annotator_id: 2, score, feedback });
      setSuccess('Rating submitted successfully');
      setError('');
      const ratingData = await getRatingsForResponse(responseId);
      setRatings(prev => ({ ...prev, [responseId]: ratingData }));
    } catch (err: any) {
      setError(err.response?.data?.detail || 'Failed to submit rating');
    }
  };

  const getSpeedColor = (time: number) => {
    if (time < 2) return '#34d399';
    if (time < 5) return '#fbbf24';
    return '#f87171';
  };

  const getSpeedLabel = (time: number) => {
    if (time < 2) return '⚡ Fast';
    if (time < 5) return '🔶 Medium';
    return '🐢 Slow';
  };

  const modelColors: { [key: string]: string } = {
    'llama-3.3-70b (Groq)': '#f97316',
    'gemini-2.0-flash': '#0ea5e9',
    'mistral-7b (Ollama)': '#8b5cf6',
  };

  return (
    <div style={{ padding: '3rem 2rem', maxWidth: '900px', margin: '0 auto' }}>

      <div style={{ marginBottom: '2rem', animation: 'fadeInUp 0.5s ease both' }}>
        <h1 style={{ color: 'white', fontWeight: 800, fontSize: '2rem', marginBottom: '0.4rem' }}>
          Rate Responses
        </h1>
        <p style={{ color: 'rgba(255,255,255,0.45)', fontSize: '0.95rem' }}>
          Select a task to compare AI responses ranked by speed. Submit ratings to build training data.
        </p>
      </div>

      {/* Task selector */}
      <div style={{ marginBottom: '2rem', animation: 'fadeInUp 0.5s ease 0.1s both' }}>
        <h2 style={{ color: 'rgba(255,255,255,0.7)', fontSize: '0.85rem', fontWeight: 700,
          letterSpacing: '0.8px', marginBottom: '0.85rem' }}>
          SELECT A TASK
        </h2>
        {tasks.map((task, i) => (
          <div
            key={task.id}
            onClick={() => handleSelectTask(task.id)}
            style={{
              padding: '1rem 1.25rem',
              border: selectedTask === task.id
                ? '1px solid rgba(99,102,241,0.6)'
                : '1px solid rgba(255,255,255,0.07)',
              borderRadius: '12px',
              marginBottom: '0.6rem',
              cursor: 'pointer',
              background: selectedTask === task.id
                ? 'rgba(99,102,241,0.12)'
                : 'rgba(255,255,255,0.03)',
              backdropFilter: 'blur(12px)',
              transition: 'all 0.2s ease',
              animation: `fadeInUp 0.4s ease ${i * 0.05}s both`
            }}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span style={{ fontWeight: 700, color: 'rgba(255,255,255,0.5)', fontSize: '0.78rem' }}>
                TASK #{task.id}
              </span>
              <span style={{
                background: task.status === 'completed'
                  ? 'rgba(16,185,129,0.15)'
                  : 'rgba(245,158,11,0.15)',
                color: task.status === 'completed' ? '#34d399' : '#fbbf24',
                padding: '0.15rem 0.6rem',
                borderRadius: '999px',
                fontSize: '0.75rem',
                fontWeight: 600,
                border: `1px solid ${task.status === 'completed'
                  ? 'rgba(52,211,153,0.3)'
                  : 'rgba(251,191,36,0.3)'}`
              }}>
                {task.status}
              </span>
            </div>
            <p style={{ color: 'rgba(255,255,255,0.8)', marginTop: '0.35rem', fontSize: '0.9rem' }}>
              {task.prompt}
            </p>
          </div>
        ))}
      </div>

      {/* No responses */}
      {selectedTask && responses.length === 0 && (
        <p style={{ color: 'rgba(255,255,255,0.35)' }}>No responses for this task yet.</p>
      )}

      {/* Responses header */}
      {responses.length > 0 && (
        <div style={{ marginBottom: '1rem' }}>
          <h2 style={{ color: 'rgba(255,255,255,0.7)', fontSize: '0.85rem', fontWeight: 700, letterSpacing: '0.8px' }}>
            AI RESPONSES — SORTED BY SPEED
          </h2>
        </div>
      )}

      {/* Response cards */}
      {responses.map((response, index) => {
        const modelColor = modelColors[response.ai_model] || '#6366f1';
        return (
          <div key={response.id} style={{
            background: 'rgba(255,255,255,0.04)',
            backdropFilter: 'blur(20px)',
            WebkitBackdropFilter: 'blur(20px)',
            border: '1px solid rgba(255,255,255,0.08)',
            borderRadius: '16px',
            padding: '1.5rem',
            marginBottom: '1.5rem',
            animation: `fadeInUp 0.4s ease ${index * 0.08}s both`,
            borderLeft: `3px solid ${modelColor}`
          }}>
            {/* Model header */}
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1rem' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                <span style={{
                  background: `linear-gradient(135deg, ${modelColor}40, ${modelColor}20)`,
                  color: modelColor,
                  borderRadius: '8px',
                  padding: '0.25rem 0.6rem',
                  fontSize: '0.75rem',
                  fontWeight: 800,
                  border: `1px solid ${modelColor}40`
                }}>
                  #{index + 1}
                </span>
                <span style={{ fontWeight: 700, color: 'white', fontSize: '0.95rem' }}>
                  {response.ai_model}
                </span>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '0.6rem' }}>
                <span style={{
                  color: getSpeedColor(response.response_time),
                  fontSize: '0.8rem',
                  fontWeight: 600
                }}>
                  {getSpeedLabel(response.response_time)}
                </span>
                <span style={{
                  color: 'rgba(255,255,255,0.3)',
                  fontSize: '0.82rem',
                  fontFamily: 'monospace'
                }}>
                  {response.response_time}s
                </span>
              </div>
            </div>

            {/* Response text */}
            <p style={{
              color: 'rgba(255,255,255,0.8)',
              lineHeight: '1.7',
              marginBottom: '1.25rem',
              fontSize: '0.92rem',
              padding: '1rem',
              background: 'rgba(255,255,255,0.04)',
              borderRadius: '10px',
              border: '1px solid rgba(255,255,255,0.06)'
            }}>
              {response.response_text}
            </p>

            {/* Existing ratings */}
            {ratings[response.id]?.length > 0 && (
              <div style={{
                marginBottom: '1rem',
                padding: '0.85rem',
                background: 'rgba(16,185,129,0.08)',
                borderRadius: '10px',
                border: '1px solid rgba(52,211,153,0.2)'
              }}>
                <p style={{ fontWeight: 700, marginBottom: '0.5rem', fontSize: '0.8rem', color: '#34d399', letterSpacing: '0.5px' }}>
                  SUBMITTED RATINGS
                </p>
                {ratings[response.id].map(rating => (
                  <div key={rating.id} style={{ fontSize: '0.85rem', color: 'rgba(255,255,255,0.6)', marginBottom: '0.25rem' }}>
                    ⭐ {rating.score}/5 — {rating.feedback}
                  </div>
                ))}
              </div>
            )}

            {/* Rating form */}
            <div>
              <p style={{ fontWeight: 600, marginBottom: '0.6rem', fontSize: '0.85rem', color: 'rgba(255,255,255,0.5)', letterSpacing: '0.5px' }}>
                YOUR RATING
              </p>
              <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '0.85rem' }}>
                {[1, 2, 3, 4, 5].map(num => (
                  <button
                    key={num}
                    onClick={() => setScores(prev => ({ ...prev, [response.id]: num }))}
                    style={{
                      width: '44px',
                      height: '44px',
                      borderRadius: '10px',
                      border: scores[response.id] === num
                        ? `2px solid ${modelColor}`
                        : '1px solid rgba(255,255,255,0.12)',
                      background: scores[response.id] === num
                        ? `${modelColor}30`
                        : 'rgba(255,255,255,0.04)',
                      color: scores[response.id] === num ? modelColor : 'rgba(255,255,255,0.5)',
                      cursor: 'pointer',
                      fontWeight: 700,
                      fontSize: '1rem',
                      transition: 'all 0.15s ease'
                    }}
                  >
                    {num}
                  </button>
                ))}
              </div>
              <textarea
                placeholder="Optional feedback..."
                value={feedbacks[response.id] || ''}
                onChange={(e) => setFeedbacks(prev => ({ ...prev, [response.id]: e.target.value }))}
                style={{
                  width: '100%',
                  minHeight: '70px',
                  padding: '0.7rem',
                  borderRadius: '10px',
                  border: '1px solid rgba(255,255,255,0.1)',
                  background: 'rgba(255,255,255,0.04)',
                  color: 'white',
                  fontSize: '0.9rem',
                  marginBottom: '0.85rem',
                  boxSizing: 'border-box',
                  resize: 'vertical',
                  outline: 'none'
                }}
              />
              <button
                onClick={() => handleSubmitRating(response.id)}
                style={{
                  background: `linear-gradient(135deg, ${modelColor}cc, ${modelColor}99)`,
                  color: 'white',
                  border: 'none',
                  padding: '0.55rem 1.4rem',
                  borderRadius: '10px',
                  cursor: 'pointer',
                  fontSize: '0.9rem',
                  fontWeight: 600,
                  boxShadow: `0 4px 15px ${modelColor}40`,
                  transition: 'all 0.2s ease'
                }}
              >
                Submit Rating
              </button>
            </div>
          </div>
        );
      })}

      {error && (
        <div style={{
          color: '#f87171', padding: '0.85rem 1rem',
          background: 'rgba(248,113,113,0.1)',
          border: '1px solid rgba(248,113,113,0.25)',
          borderRadius: '10px', marginTop: '1rem', fontSize: '0.9rem'
        }}>
          {error}
        </div>
      )}
      {success && (
        <div style={{
          color: '#34d399', padding: '0.85rem 1rem',
          background: 'rgba(52,211,153,0.1)',
          border: '1px solid rgba(52,211,153,0.25)',
          borderRadius: '10px', marginTop: '1rem', fontSize: '0.9rem'
        }}>
          {success}
        </div>
      )}
    </div>
  );
};

export default RatingsPage;
